operation.add:
        // Final check
        if($order_info['order_status_id'] != $this->request->post['order_status_id'] && $order_info['payment_code'] == 'robokassa' && $this->request->post['order_status_id'] == $this->config->get('payment_robokassa_order_status_id_2check') && $this->config->get('payment_robokassa_fiscal') == 1){
		  $this->load->model('extension/payment/robokassa');

		  $this->model_extension_payment_robokassa->sendSecondCheck($order_id);
		}
        // Final check

        // Added condition for robokassa_hold_confirm
        if ($order_info['order_status_id'] == 1 && $this->request->post['order_status_id'] == 2) {
          $this->load->model('extension/payment/robokassa');
          $this->model_extension_payment_robokassa->robokassa_hold_confirm($order_id);
        }
        // Added condition for robokassa_hold_confirm

        // Added condition for robokassa_hold_cancel
        if ($order_info['order_status_id'] == 1 && $this->request->post['order_status_id'] == 7) {
          $this->load->model('extension/payment/robokassa');
          $this->model_extension_payment_robokassa->robokassa_hold_cancel($order_id);
        }
        // Added condition for robokassa_hold_cancel

$data['robokassa_widget'] = '';

if ($this->config->get('payment_robokassa_country') == 'RUB') {
  if ($this->customer->isLogged() || !$this->config->get('config_customer_price')) {
    if ((float)$product_info['special']) {
      $robokassa_widget_amount = $this->tax->calculate($product_info['special'], $product_info['tax_class_id'], $this->config->get('config_tax'));
    } else {
      $robokassa_widget_amount = $this->tax->calculate($product_info['price'], $product_info['tax_class_id'], $this->config->get('config_tax'));
    }

    if ($robokassa_widget_amount > 0) {
      $data['robokassa_widget'] = $this->load->controller('extension/payment/robokassa_widget', array(
        'product_id' => $product_id,
        'quantity' => isset($this->request->get['quantity']) ? (int)$this->request->get['quantity'] : $data['minimum']
      ));
    }
  }
}

$robokassa_installment_map = array(
  'robokassa_podeli' => 'podeli',
  'robokassa_credit' => 'otp',
  'robokassa_mokka' => 'mokka',
  'robokassa_yandex_split' => 'yandexpaysplit',
  'robokassa_split' => 'yandexpaysplit'
);
$robokassa_bnpl_aliases = array('podeli', 'otp', 'mokka', 'yandexpaysplit');
$robokassa_installment_aliases = array();
$robokassa_methods_initialized = (int)$this->config->get('payment_robokassa_methods_initialized') === 1;
$robokassa_current_login = trim((string)$this->config->get('payment_robokassa_login'));
$robokassa_saved_login = trim((string)$this->config->get('payment_robokassa_methods_login'));
$robokassa_merchant_login = ($robokassa_methods_initialized && $robokassa_current_login !== '' && $robokassa_saved_login === $robokassa_current_login) ? $robokassa_saved_login : '';

if ($robokassa_merchant_login !== '') {
  $robokassa_currency_url = 'https://auth.robokassa.ru/Merchant/WebService/Service.asmx/GetCurrencies?MerchantLogin=' . rawurlencode($robokassa_merchant_login) . '&Language=ru';
  $robokassa_currency_xml = false;

  if (function_exists('curl_init')) {
    $robokassa_ch = curl_init($robokassa_currency_url);
    curl_setopt($robokassa_ch, CURLOPT_RETURNTRANSFER, true);
    curl_setopt($robokassa_ch, CURLOPT_CONNECTTIMEOUT, 3);
    curl_setopt($robokassa_ch, CURLOPT_TIMEOUT, 3);
    $robokassa_currency_xml = curl_exec($robokassa_ch);
    curl_close($robokassa_ch);
  }

  if ($robokassa_currency_xml === false && ini_get('allow_url_fopen')) {
    $robokassa_currency_context = stream_context_create(array(
      'http' => array(
        'timeout' => 3
      )
    ));
    $robokassa_currency_xml = @file_get_contents($robokassa_currency_url, false, $robokassa_currency_context);
  }

  if ($robokassa_currency_xml !== false && strpos($robokassa_currency_xml, '<Code>0</Code>') !== false && preg_match_all('/\bAlias="([^"]+)"/i', $robokassa_currency_xml, $robokassa_aliases_match)) {
    foreach ($robokassa_aliases_match[1] as $robokassa_alias) {
      $robokassa_installment_aliases[] = strtolower((string)$robokassa_alias);
    }

    $robokassa_installment_aliases = array_unique($robokassa_installment_aliases);
  }
}

if ($extension == 'payment' && $files) {
  $robokassa_installment_map = array(
    'robokassa_podeli' => 'podeli',
    'robokassa_credit' => 'otp',
    'robokassa_mokka' => 'mokka',
    'robokassa_yandex_split' => 'yandexpaysplit',
    'robokassa_split' => 'yandexpaysplit'
  );
  $robokassa_bnpl_aliases = array('podeli', 'otp', 'mokka', 'yandexpaysplit');
  $robokassa_installment_aliases = array();
  $robokassa_methods_initialized = (int)$this->config->get('payment_robokassa_methods_initialized') === 1;
  $robokassa_current_login = trim((string)$this->config->get('payment_robokassa_login'));
  $robokassa_saved_login = trim((string)$this->config->get('payment_robokassa_methods_login'));
  $robokassa_merchant_login = ($robokassa_methods_initialized && $robokassa_current_login !== '' && $robokassa_saved_login === $robokassa_current_login) ? $robokassa_saved_login : '';

  if ($robokassa_merchant_login !== '') {
    $robokassa_currency_url = 'https://auth.robokassa.ru/Merchant/WebService/Service.asmx/GetCurrencies?MerchantLogin=' . rawurlencode($robokassa_merchant_login) . '&Language=ru';
    $robokassa_currency_xml = false;

    if (function_exists('curl_init')) {
      $robokassa_ch = curl_init($robokassa_currency_url);
      curl_setopt($robokassa_ch, CURLOPT_RETURNTRANSFER, true);
      curl_setopt($robokassa_ch, CURLOPT_CONNECTTIMEOUT, 3);
      curl_setopt($robokassa_ch, CURLOPT_TIMEOUT, 3);
      $robokassa_currency_xml = curl_exec($robokassa_ch);
      curl_close($robokassa_ch);
    }

    if ($robokassa_currency_xml === false && ini_get('allow_url_fopen')) {
      $robokassa_currency_context = stream_context_create(array(
        'http' => array(
          'timeout' => 3
        )
      ));
      $robokassa_currency_xml = @file_get_contents($robokassa_currency_url, false, $robokassa_currency_context);
    }

    if ($robokassa_currency_xml !== false && strpos($robokassa_currency_xml, '<Code>0</Code>') !== false && preg_match_all('/\bAlias="([^"]+)"/i', $robokassa_currency_xml, $robokassa_aliases_match)) {
      foreach ($robokassa_aliases_match[1] as $robokassa_alias) {
        $robokassa_installment_aliases[] = strtolower((string)$robokassa_alias);
      }

      $robokassa_installment_aliases = array_unique($robokassa_installment_aliases);
    }
  }

  $robokassa_payment_files = array();

  foreach ($files as $robokassa_file) {
    $robokassa_code = basename($robokassa_file, '.php');

    if (isset($robokassa_installment_map[$robokassa_code]) && !in_array($robokassa_installment_map[$robokassa_code], $robokassa_installment_aliases, true)) {
      continue;
    }

    if ($robokassa_code == 'robokassa_widget' && !array_intersect($robokassa_bnpl_aliases, $robokassa_installment_aliases)) {
      continue;
    }

    $robokassa_payment_files[] = $robokassa_file;
  }

  $files = $robokassa_payment_files;
}
